import{_ as o,o as s,c as a,ag as i}from"./chunks/framework.CTpQozEL.js";const k=JSON.parse('{"title":"샌드박스 vs 도구 정책 vs 상승된 권한","description":"도구가 차단된 이유: 샌드박스 런타임, 도구 허용/거부 정책, 상승된 exec 게이트","frontmatter":{"title":"샌드박스 vs 도구 정책 vs 상승된 권한","description":"도구가 차단된 이유: 샌드박스 런타임, 도구 허용/거부 정책, 상승된 exec 게이트"},"headers":[],"relativePath":"gateway/sandbox-vs-tool-policy-vs-elevated.md","filePath":"gateway/sandbox-vs-tool-policy-vs-elevated.md","lastUpdated":null}'),l={name:"gateway/sandbox-vs-tool-policy-vs-elevated.md"};function d(t,e,n,c,p,r){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="샌드박스-vs-도구-정책-vs-상승된-권한" tabindex="-1">샌드박스 vs 도구 정책 vs 상승된 권한 <a class="header-anchor" href="#샌드박스-vs-도구-정책-vs-상승된-권한" aria-label="Permalink to &quot;샌드박스 vs 도구 정책 vs 상승된 권한&quot;">​</a></h1><p>OpenClaw에는 세 가지 관련된(하지만 다른) 제어가 있습니다:</p><ol><li><strong>샌드박스</strong> (<code>agents.defaults.sandbox.*</code> / <code>agents.list[].sandbox.*</code>)는 <strong>도구가 실행되는 위치</strong>를 결정합니다 (Docker vs 호스트).</li><li><strong>도구 정책</strong> (<code>tools.*</code>, <code>tools.sandbox.tools.*</code>, <code>agents.list[].tools.*</code>)는 <strong>어떤 도구를 사용할 수 있는지/허용되는지</strong>를 결정합니다.</li><li><strong>상승된 권한</strong> (<code>tools.elevated.*</code>, <code>agents.list[].tools.elevated.*</code>)은 샌드박스 상태일 때 샌드박스 외부에서 실행하기 위한 <strong>exec 전용 탈출구</strong>입니다(기본적으로 <code>gateway</code>, 또는 exec 대상이 <code>node</code>로 구성된 경우 <code>node</code>).</li></ol><h2 id="빠른-디버그" tabindex="-1">빠른 디버그 <a class="header-anchor" href="#빠른-디버그" aria-label="Permalink to &quot;빠른 디버그&quot;">​</a></h2><p>인스펙터를 사용하여 OpenClaw가 실제로 수행하는 작업을 확인합니다:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --session</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agent:main:main</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> work</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre></div><p>출력 내용:</p><ul><li>효과적인 샌드박스 모드/범위/워크스페이스 액세스</li><li>세션이 현재 샌드박스됨(메인 vs 비메인) 여부</li><li>효과적인 샌드박스 도구 허용/거부 (에이전트/전역/기본값에서 온 것인지 여부 포함)</li><li>상승된 게이트 및 수정 키 경로</li></ul><h2 id="샌드박스-도구가-실행되는-위치" tabindex="-1">샌드박스: 도구가 실행되는 위치 <a class="header-anchor" href="#샌드박스-도구가-실행되는-위치" aria-label="Permalink to &quot;샌드박스: 도구가 실행되는 위치&quot;">​</a></h2><p>샌드박싱은 <code>agents.defaults.sandbox.mode</code>로 제어됩니다:</p><ul><li><code>&quot;off&quot;</code>: 모든 것이 호스트에서 실행됩니다.</li><li><code>&quot;non-main&quot;</code>: 비메인 세션만 샌드박스됩니다 (그룹/채널에 대한 일반적인 &quot;놀라움&quot;).</li><li><code>&quot;all&quot;</code>: 모든 것이 샌드박스됩니다.</li></ul><p>전체 매트릭스(범위, 워크스페이스 마운트, 이미지)는 <a href="/openclaw-docs-ko/gateway/sandboxing">샌드박싱</a>을 참조하십시오.</p><h3 id="바인드-마운트-보안-빠른-체크" tabindex="-1">바인드 마운트 (보안 빠른 체크) <a class="header-anchor" href="#바인드-마운트-보안-빠른-체크" aria-label="Permalink to &quot;바인드 마운트 (보안 빠른 체크)&quot;">​</a></h3><ul><li><code>docker.binds</code>는 샌드박스 파일 시스템을 <em>관통합니다</em>: 마운트한 것이 설정한 모드(<code>:ro</code> 또는 <code>:rw</code>)로 컨테이너 내에 표시됩니다.</li><li>모드를 생략하면 기본값은 읽기-쓰기입니다; 소스/시크릿에는 <code>:ro</code>를 사용합니다.</li><li><code>scope: &quot;shared&quot;</code>는 에이전트별 바인드를 무시합니다 (전역 바인드만 적용).</li><li>OpenClaw는 바인드 소스를 두 번 검증합니다: 먼저 정규화된 소스 경로에서, 그런 다음 가장 깊은 기존 조상을 통해 해결한 후. 심링크-부모 탈출은 차단된 경로 또는 허용된 루트 검사를 우회하지 않습니다.</li><li><code>/var/run/docker.sock</code>을 바인딩하면 호스트 제어를 샌드박스에 효과적으로 넘깁니다; 의도적으로만 수행합니다.</li></ul><h2 id="도구-정책-어떤-도구가-존재-호출-가능한지" tabindex="-1">도구 정책: 어떤 도구가 존재/호출 가능한지 <a class="header-anchor" href="#도구-정책-어떤-도구가-존재-호출-가능한지" aria-label="Permalink to &quot;도구 정책: 어떤 도구가 존재/호출 가능한지&quot;">​</a></h2><p>두 가지 레이어가 중요합니다:</p><ul><li><strong>도구 프로필</strong>: <code>tools.profile</code> 및 <code>agents.list[].tools.profile</code> (기본 허용 목록)</li><li><strong>프로바이더 도구 프로필</strong>: <code>tools.byProvider[provider].profile</code> 및 <code>agents.list[].tools.byProvider[provider].profile</code></li><li><strong>전역/에이전트별 도구 정책</strong>: <code>tools.allow</code>/<code>tools.deny</code> 및 <code>agents.list[].tools.allow</code>/<code>agents.list[].tools.deny</code></li><li><strong>샌드박스 도구 정책</strong> (샌드박스 상태일 때만 적용): <code>tools.sandbox.tools.allow</code>/<code>tools.sandbox.tools.deny</code> 및 <code>agents.list[].tools.sandbox.tools.*</code></li></ul><p>경험칙:</p><ul><li><code>deny</code>는 항상 이깁니다.</li><li><code>allow</code>가 비어 있지 않으면 다른 모든 것은 차단된 것으로 취급됩니다.</li><li>도구 정책은 완전 차단입니다: <code>/exec</code>은 거부된 <code>exec</code> 도구를 재정의할 수 없습니다.</li><li><code>/exec</code>는 인증된 발신자에 대한 세션 기본값만 변경합니다; 도구 액세스를 부여하지 않습니다.</li></ul><h3 id="도구-그룹-약어" tabindex="-1">도구 그룹 (약어) <a class="header-anchor" href="#도구-그룹-약어" aria-label="Permalink to &quot;도구 그룹 (약어)&quot;">​</a></h3><p>도구 정책(전역, 에이전트, 샌드박스)은 여러 도구로 확장되는 <code>group:*</code> 항목을 지원합니다:</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    sandbox</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        allow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:runtime&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:fs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:sessions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:memory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>사용 가능한 그룹:</p><ul><li><code>group:runtime</code>: <code>exec</code>, <code>process</code>, <code>code_execution</code></li><li><code>group:fs</code>: <code>read</code>, <code>write</code>, <code>edit</code>, <code>apply_patch</code></li><li><code>group:sessions</code>: <code>sessions_list</code>, <code>sessions_history</code>, <code>sessions_send</code>, <code>sessions_spawn</code>, <code>sessions_yield</code>, <code>subagents</code>, <code>session_status</code></li><li><code>group:memory</code>: <code>memory_search</code>, <code>memory_get</code></li><li><code>group:web</code>: <code>web_search</code>, <code>x_search</code>, <code>web_fetch</code></li><li><code>group:ui</code>: <code>browser</code>, <code>canvas</code></li><li><code>group:automation</code>: <code>cron</code>, <code>gateway</code></li><li><code>group:messaging</code>: <code>message</code></li><li><code>group:nodes</code>: <code>nodes</code></li><li><code>group:agents</code>: <code>agents_list</code></li><li><code>group:media</code>: <code>image</code>, <code>image_generate</code>, <code>video_generate</code>, <code>tts</code></li><li><code>group:openclaw</code>: 모든 내장 OpenClaw 도구 (프로바이더 플러그인 제외)</li></ul><h2 id="상승된-권한-exec-전용-호스트에서-실행" tabindex="-1">상승된 권한: exec 전용 &quot;호스트에서 실행&quot; <a class="header-anchor" href="#상승된-권한-exec-전용-호스트에서-실행" aria-label="Permalink to &quot;상승된 권한: exec 전용 &quot;호스트에서 실행&quot;&quot;">​</a></h2><p>상승된 권한은 추가 도구를 <strong>부여하지 않습니다</strong>; <code>exec</code>에만 영향을 미칩니다.</p><ul><li>샌드박스 상태이면 <code>/elevated on</code>(또는 <code>elevated: true</code>인 <code>exec</code>)이 샌드박스 외부에서 실행됩니다 (승인이 여전히 적용될 수 있음).</li><li>세션에 대한 exec 승인을 건너뛰려면 <code>/elevated full</code>을 사용합니다.</li><li>이미 직접 실행 중이라면 상승된 권한은 사실상 아무런 효과가 없습니다 (여전히 게이팅됨).</li><li>상승된 권한은 skill 범위가 아니며 도구 허용/거부를 재정의하지 <strong>않습니다</strong>.</li></ul><p>게이트:</p><ul><li>활성화: <code>tools.elevated.enabled</code> (및 선택적으로 <code>agents.list[].tools.elevated.enabled</code>)</li><li>발신자 허용 목록: <code>tools.elevated.allowFrom.&lt;provider&gt;</code> (및 선택적으로 <code>agents.list[].tools.elevated.allowFrom.&lt;provider&gt;</code>)</li></ul><p><a href="/openclaw-docs-ko/tools/elevated">상승된 모드</a> 참조.</p><h2 id="일반적인-sandbox-jail-수정" tabindex="-1">일반적인 &quot;sandbox jail&quot; 수정 <a class="header-anchor" href="#일반적인-sandbox-jail-수정" aria-label="Permalink to &quot;일반적인 &quot;sandbox jail&quot; 수정&quot;">​</a></h2><h3 id="도구-x가-샌드박스-도구-정책에-의해-차단됨" tabindex="-1">&quot;도구 X가 샌드박스 도구 정책에 의해 차단됨&quot; <a class="header-anchor" href="#도구-x가-샌드박스-도구-정책에-의해-차단됨" aria-label="Permalink to &quot;&quot;도구 X가 샌드박스 도구 정책에 의해 차단됨&quot;&quot;">​</a></h3><p>수정 키 (하나 선택):</p><ul><li>샌드박스 비활성화: <code>agents.defaults.sandbox.mode=off</code> (또는 에이전트별 <code>agents.list[].sandbox.mode=off</code>)</li><li>샌드박스 내에서 도구 허용: <ul><li><code>tools.sandbox.tools.deny</code>에서 제거 (또는 에이전트별 <code>agents.list[].tools.sandbox.tools.deny</code>)</li><li>또는 <code>tools.sandbox.tools.allow</code>에 추가 (또는 에이전트별 허용)</li></ul></li></ul><h3 id="이것이-메인이라고-생각했는데-왜-샌드박스됐나요" tabindex="-1">&quot;이것이 메인이라고 생각했는데, 왜 샌드박스됐나요?&quot; <a class="header-anchor" href="#이것이-메인이라고-생각했는데-왜-샌드박스됐나요" aria-label="Permalink to &quot;&quot;이것이 메인이라고 생각했는데, 왜 샌드박스됐나요?&quot;&quot;">​</a></h3><p><code>&quot;non-main&quot;</code> 모드에서 그룹/채널 키는 메인이 <em>아닙니다</em>. 메인 세션 키(<code>sandbox explain</code>으로 표시됨)를 사용하거나 모드를 <code>&quot;off&quot;</code>로 전환합니다.</p><h2 id="참조" tabindex="-1">참조 <a class="header-anchor" href="#참조" aria-label="Permalink to &quot;참조&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/gateway/sandboxing">샌드박싱</a> -- 전체 샌드박스 참조 (모드, 범위, 백엔드, 이미지)</li><li><a href="/openclaw-docs-ko/tools/multi-agent-sandbox-tools">멀티 에이전트 샌드박스 및 도구</a> -- 에이전트별 재정의 및 우선순위</li><li><a href="/openclaw-docs-ko/tools/elevated">상승된 모드</a></li></ul>`,38)])])}const g=o(l,[["render",d]]);export{k as __pageData,g as default};
